var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 바람대로 와일러는 다시 감옥에 수감되었네.","JPN":"君の望み通り、ワイラーは再び刑務所に収監された。","ENG":"Wyler's been put back into jail, just like you wanted.","TWN":"如你所願，瓦勒被重新收監。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조니 앤 멜로니도 이번에는 쉽게 그 자를 빼낼 수 없을 거야.","JPN":"ジョニー＆メロニーでも、今度はそう簡単に刑務所から出すことはできないだろう。","ENG":"Even Jonie & Melonie will have a hard time getting him out now.","TWN":"這次就算是強尼＆梅蘭妮也很難把他弄出來吧。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 애초에 이젠 스폰서들이 그 자를 찾을 이유가 없겠지.","JPN":"いや、そもそも、もう彼を欲しがる理由がない。","ENG":"No, better yet, there won't be a reason for sponsors to hire him anymore.","TWN":"不，既然贊助商已經不需要他，也就沒必要弄他出來了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잠시 자리를 피해주겠네.","JPN":"少し一人になった方がいいだろう。","ENG":"I'll let you have a minute.","TWN":"我讓你自己冷靜一下吧。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"감사합니다. 사장님.","JPN":"ありがとうございます。社長。","ENG":"Thank you, Boss.","TWN":"謝謝你，老闆。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"흐윽…… 흑…….","JPN":"うっ……ううっ……","ENG":"*Sniffle...* Hnnggh...","TWN":"嗚嗚……嗚……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"유명한 여배우를 여기서 만나게 될 줄은 몰랐는데.","JPN":"こんなところで大女優に会うとはな。","ENG":"I never thought I'd encounter a famous actress here.","TWN":"沒想到會在這裡遇到知名女演員。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신을 기억하고 있어요.","JPN":"あなたを覚えています。","ENG":"I remember you.","TWN":"我記得你。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"첫 만남은 기자들 때문에 소란스러웠는데, 지금은 무척 고요하네요.","JPN":"初対面のときは記者がいてうるさかったですが、今はとても静かですね。","ENG":"The first time we met, it was so loud with all those reporters. But now, it is silent.","TWN":"第一次見面的時候因為記者的關係吵吵鬧鬧的，現在倒是很安靜呢。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나도 어째선지 자네가 낯설지 않군.","JPN":"私も何だか君に馴染みがある。","ENG":"For some reason, I also believe we have met before.","TWN":"不知為何，我對你並不感到陌生。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여기는 본래 대정화 전쟁의 전몰자 묘역이라네.","JPN":"ここは本来大浄化戦争の戦没者の墓地だった。","ENG":"This place originally used to be a graveyard for those who died in the Grand Purification War.","TWN":"這裡原本是淨化之戰烈士的墓園。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"죽은 가족들 곁에 묻히고 싶어하는 이들 때문에 주위에 일반 묘역이 생겨났지.","JPN":"亡くなった家族のそばに葬られたいという者たちのために、周りには一般墓地が作られた。","ENG":"However, because some people preferred to be buried near their families, a second general-use graveyard was built nearby.","TWN":"只是因為遺族希望能葬在死去的家人身旁，於是周圍多出很多普通的墓碑。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네 가족 중에도 전쟁 중에 희생된 분이 계시나?","JPN":"君の家族にも戦争で亡くなった方がいるのか？","ENG":"Do you happen to have a family member who died in the war by chance?","TWN":"你的家人也是在戰爭中犧牲的人嗎？"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 그저 희생된 이들에게 애도를 표하고 싶었을 뿐입니다.","JPN":"いいえ。私はただ犠牲になった方々への哀悼の意を表したかっただけです。","ENG":"No. I am here to express my condolences for those who had sacrificed their lives.","TWN":"不，我只是想向亡者致哀而已。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"준결승전은 잘 봤습니다. 부족한 병사들을 잘 지휘해 주시더군요.","JPN":"準決勝戦を見ました。欠点の多いメンバーたちを見事に指揮しておられましたね。","ENG":"I enjoyed watching the semifinal match. You commanded those inept soldiers quite well.","TWN":"我有看準決賽，你很會指揮能力不佳的小兵。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙네, 하지만 그렇게 보였다면 부족한 부분을 채워 주지 못한 내 잘못이겠지.","JPN":"そうか、感謝する。しかしそう見えていたのなら、その欠点をなんとかしてやれなかった私の責任だろう。","ENG":"Thank you. But if you could see that they were inept, then it's my fault that I couldn't do better.","TWN":"謝謝你，不過如果他們能力不佳，那都要怪我沒能訓練好他們。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……책임감이 과하면 독이 되기 마련이죠.","JPN":"……強すぎる責任感は身を滅ぼします。","ENG":"...Too much responsibility can be poisonous.","TWN":"……給自己壓力太大是會走火入魔的。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 목표는 명확하지 않나요?","JPN":"あなたの目標は明確なのではありませんか？","ENG":"And your goals are clear, are they not?","TWN":"你的目標很明確吧？"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금은 잠시 숨을 고르고 계실 시기 아닐까요. 더 많은 짐을 짊어지는 대신에.","JPN":"今はしばらく休まれた方が良いと思います。より多くの荷を背負うのではなく。","ENG":"I believe you are merely catching your breath for the time being. For you have a heavier burden to carry later.","TWN":"對於將來要背負更多重擔的你來說，正好可以趁現在稍微喘口氣吧？"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"참견이 심했네요. 결승전도 기대하겠습니다.","JPN":"余計な口出しでしたね。決勝戦も楽しみにしています。","ENG":"Forgive me for prying. Then, I shall look forward to the finals.","TWN":"是我多事了，我很期待決賽。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼 이만…….","JPN":"それでは……","ENG":"Now, if you will excuse me...","TWN":"先告辭……"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니, 최근에 누군가가 나를 몰래 돕고 있다고 생각하던 참이었지.","JPN":"そういうば、最近誰かに陰から助けられているという気がしていたところだったが。","ENG":"Now that you mention it, I have been thinking that someone has been secretly helping me recently.","TWN":"對了，最近我一直覺得有人在偷偷幫助我。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"예선 마지막 경기 중에 생긴 트러블이 한 발 앞서 해결되었다거나.","JPN":"予選での最終戦でも、試合中に起きたトラブルが一足先に解決していたり。","ENG":"For instance, an issue that occurred during the qualifiers was resolved one step ahead.","TWN":"像是在預賽的最後一場比賽中發生的問題，先一步被人解決掉。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리를 공격 해 온 침식체가 갑자기 사라져 버렸다거나.","JPN":"私たちを攻撃してきた侵食体がいきなり蒸発したり。","ENG":"And another time, the C.O.s that were attacking us suddenly disappeared.","TWN":"或者攻擊我們的侵蝕體突然消失。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"분명 나타날 거라고 예상했던 3종 침식체가 잠잠하다거나.","JPN":"現れるはずだった第3種侵食体が現れなかったり。","ENG":"Even the Category 3 C.O. that I was expecting to appear did not show up.","TWN":"又或者明明該出現3類侵蝕體卻沒有出現。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리를 몰래 돕고 있는 게 아마도 자네라고 생각하는데.","JPN":"私たちを密かに助けているのは、おそらく君だと思うが。","ENG":"I think that you are the one who has been secretly assisting us.","TWN":"我認為偷偷幫助我們的人就是你。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹시 이유를 물어봐도 괜찮을까?","JPN":"その理由が何なのか聞いてもいいかね？","ENG":"May I ask why?","TWN":"我能問你為什麼這麼做嗎？"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……글쎄요. 저는 그저 응원하고 있을 뿐이랍니다.","JPN":"……さあ。私はただ応援がしたいだけなんです。","ENG":"...Well. I was merely rooting for you.","TWN":"……怎麼說呢，我只是為你們加油而已。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"팬이니까요. 당신의.","JPN":"ファンですから。あなたの。","ENG":"Because I am a fan. Of yours.","TWN":"因為我是你的粉絲。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"질문에 대답이 되었을까요?","JPN":"答えになったでしょうか？","ENG":"Does that answer your question?","TWN":"不知道我的回答有沒有解除你的疑惑？"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠…… 응원은 감사히 받겠네. 사인은 못 해 주겠지만 말이야.","JPN":"ふむ……応援には感謝する。サインはしてあげられないが。","ENG":"Hmm... I appreciate your support. But I won't be able to give you an autograph.","TWN":"唔……感謝你的支持，不過我不能幫你簽名。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗, 그건 조금 아쉽네요.","JPN":"ふふっ、それはちょっぴり残念ですね。","ENG":"Fu fuu. How unfortunate.","TWN":"呵呵，好可惜。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼 사인을 받기 위해서라도, 조금쯤 도움이 되는 조언을 드려야겠군요.","JPN":"ではサインをもらうためにも、少しお役に立ちそうなアドバイスをしてさしあげましょう。","ENG":"Perhaps I can change your mind with a bit of advice.","TWN":"那為了得到你的簽名，我必須提出一個稍微有幫助的建議囉。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"노엘 라이트 양. 그녀를 너무 믿지 마세요.","JPN":"ノエル・ライト。彼女をあんまり信用してはいけません。","ENG":"Noelle Wright. Do not trust her so much.","TWN":"洛艾兒·萊特，你不要太相信她。"},"stage":{"bg":"TOMB","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};